#!/usr/bin/env Rscript
#
# Task: T036b - Validate SC-006
# Description: Check per-region regression summary to confirm >=80% of regions 
#              produced computable results.
#
# Input: results/regression_by_region.csv (generated by analyze_shifts.R)
# Output: results/validation_sc006.json (validation report)
#         Console: Exit code 0 if pass, 1 if fail (or missing data)
#

library(dplyr)
library(readr)
library(jsonlite)
library(here)

# Configuration
INPUT_FILE <- here("results", "regression_by_region.csv")
OUTPUT_FILE <- here("results", "validation_sc006.json")
SUCCESS_THRESHOLD <- 0.80  # 80%

# Source utilities for consistent logging
# Note: Assuming utils.R is in src/code/ as per T004
if (file.exists(here("src", "code", "utils.R"))) {
  source(here("src", "code", "utils.R"))
} else {
  # Fallback simple logging if utils not yet fully loaded or available
  log_info <- function(msg) cat(sprintf("[%s] INFO: %s\n", Sys.time(), msg))
  log_error <- function(msg) cat(sprintf("[%s] ERROR: %s\n", Sys.time(), msg))
  log_warn <- function(msg) cat(sprintf("[%s] WARN: %s\n", Sys.time(), msg))
}

main <- function() {
  log_info("Starting SC-006 validation (T036b)...")

  # Check if input file exists
  if (!file.exists(INPUT_FILE)) {
    msg <- sprintf("Input file not found: %s. Has analyze_shifts.R been run?", INPUT_FILE)
    log_error(msg)
    
    # Write failure report
    report <- list(
      task_id = "T036b",
      validation_id = "SC-006",
      status = "FAILED",
      reason = "Input file missing",
      details = msg,
      total_regions = NA,
      valid_regions = NA,
      success_rate = NA,
      threshold = SUCCESS_THRESHOLD
    )
    write_json(report, OUTPUT_FILE, pretty = TRUE)
    quit(status = 1)
  }

  # Load data
  tryCatch({
    data <- read_csv(INPUT_FILE, show_col_types = FALSE)
  }, error = function(e) {
    msg <- sprintf("Failed to read input file: %s", e$message)
    log_error(msg)
    quit(status = 1)
  })

  log_info(sprintf("Loaded %d rows from %s", nrow(data), INPUT_FILE))

  # Define columns that indicate a "computable result"
  # Based on T023d, the file should contain slope, ci_lower, ci_upper, r_squared, p_value
  required_cols <- c("slope", "ci_lower", "ci_upper", "r_squared", "p_value")
  missing_cols <- setdiff(required_cols, names(data))

  if (length(missing_cols) > 0) {
    msg <- sprintf("Missing required columns for validation: %s", paste(missing_cols, collapse = ", "))
    log_error(msg)
    quit(status = 1)
  }

  # Calculate metrics
  total_regions <- nrow(data)
  
  # A region is "valid" if slope is not NA and p_value is not NA (and ideally finite)
  # We also check if the confidence interval is finite
  valid_mask <- 
    !is.na(data$slope) & 
    !is.na(data$p_value) & 
    is.finite(data$slope) & 
    is.finite(data$p_value) &
    is.finite(data$ci_lower) &
    is.finite(data$ci_upper)
  
  valid_regions <- sum(valid_mask)
  success_rate <- if (total_regions > 0) valid_regions / total_regions else 0

  log_info(sprintf("Total regions: %d", total_regions))
  log_info(sprintf("Valid regions: %d", valid_regions))
  log_info(sprintf("Success rate: %.2f%% (%.4f)", success_rate * 100, success_rate))

  # Determine pass/fail
  passed <- success_rate >= SUCCESS_THRESHOLD
  status <- if (passed) "PASSED" else "FAILED"

  if (passed) {
    log_info(sprintf("SC-006 Validation PASSED: %.2f%% >= %.2f%%", success_rate * 100, SUCCESS_THRESHOLD * 100))
  } else {
    log_warn(sprintf("SC-006 Validation FAILED: %.2f%% < %.2f%%", success_rate * 100, SUCCESS_THRESHOLD * 100))
    log_warn("Insufficient regions produced computable regression results.")
  }

  # Generate report
  report <- list(
    task_id = "T036b",
    validation_id = "SC-006",
    status = status,
    total_regions = total_regions,
    valid_regions = valid_regions,
    success_rate = round(success_rate, 4),
    threshold = SUCCESS_THRESHOLD,
    passed = passed,
    timestamp = Sys.time()
  )

  # Write report
  tryCatch({
    write_json(report, OUTPUT_FILE, pretty = TRUE, auto_unbox = TRUE)
    log_info(sprintf("Validation report saved to: %s", OUTPUT_FILE))
  }, error = function(e) {
    log_error(sprintf("Failed to write report: %s", e$message))
  })

  # Exit with appropriate code
  if (!passed) {
    quit(status = 1)
  }
}

main()
